const express = require('express');
const controller = require('./organization.controller');
const permit = require('../../Middleware/permit');
const { authenticate, session } = require('../../Middleware/authenticate');
const inputSanitization = require('../../Middleware/sanitization');
const { response } = require('express');

const router = express.Router();

router.get(
  '/',
  // authenticate,
  // permit('superAdmin', 'admin'),
  // session,

  controller.getOrgChild
);
router.post(
  '/',
  authenticate,
  permit('superAdmin'),
  session,

  inputSanitization.orgReg,
  controller.createOrganization
);
router.post(
  '/edit',
  authenticate,
  permit('superAdmin', 'admin'),
  session,
  inputSanitization.editOrg,
  controller.editOrganizationName
);
router.post(
  '/delete',
  authenticate,
  permit('superAdmin', 'admin'),
  session,

  controller.deleteOrganization
);


